void solve() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return;
    vector<long long> bursts(n);
    for (int i = 0; i < n; ++i) cin >> bursts[i];
    sort(bursts.begin(), bursts.end());
    long long total_wait = 0, elapsed = 0;
    for (long long b : bursts) {
        total_wait += elapsed;
        elapsed += b;
    }
    cout << total_wait << '\n';
}

// @driver-code-start
int main() {
    solve();
    return 0;
}

